1	use crate::app::state::{AppMode, Focus};
2	use crate::app::App;
3	use crate::dicom::{parse_dicom_datetime_delta_ms, DiffStatus};
4	use crate::validation::{SopClass, ValidationResult};
5	use ratatui::{
6	    layout::{Constraint, Direction, Layout, Rect},
7	    style::{Color, Modifier, Style},
8	    text::{Line, Span},
9	    widgets::{Block, Borders, Cell, Paragraph, Row, Table},
10	    Frame,
11	};
12	use ratatui_image::StatefulImage;
13	use similar::{ChangeTag, TextDiff};
14	
15	pub fn render(frame: &mut Frame, app: &mut App) {
16	    match app.mode {
17	        AppMode::Direct => render_direct(frame, app),
18	        AppMode::Explorer => render_explorer(frame, app),
19	    }
20	}
21	
22	fn render_direct(frame: &mut Frame, app: &mut App) {
23	    let full_area = frame.area();
24	
25	    let (main_area, preview_area) = if app.show_preview {
26	        let h_chunks = Layout::default()
27	            .direction(Direction::Horizontal)
28	            .constraints([Constraint::Percentage(50), Constraint::Percentage(50)])
29	            .split(full_area);
30	        (h_chunks[0], Some(h_chunks[1]))
31	    } else {
32	        (full_area, None)
33	    };
34	
35	    let validation_height = if matches!(&app.validation_result, ValidationResult::Invalid(_)) {
36	        4
37	    } else {
38	        3
39	    };
40	
41	    let chunks = Layout::default()
42	        .direction(Direction::Vertical)
43	        .constraints([Constraint::Min(5), Constraint::Length(validation_height)])
44	        .split(main_area);
45	
46	    let area = chunks[0];
47	    let validation_area = chunks[1];
48	
49	    render_validation_pane(frame, validation_area, app);
50	
51	    if let Some(preview_area) = preview_area {
52	        render_preview_pane(frame, preview_area, app);
53	    }
54	
55	    render_tag_table(frame, area, app, false);
56	    render_direct_help(frame, area, app);
57	}
58	
59	fn render_explorer(frame: &mut Frame, app: &mut App) {
60	    let full_area = frame.area();
61	    let has_dicom = app.has_dicom_loaded();
62	
63	    let columns = if has_dicom && app.show_preview {
64	        Layout::default()
65	            .direction(Direction::Horizontal)
66	            .constraints([
67	                Constraint::Percentage(25),
68	                Constraint::Percentage(40),
69	                Constraint::Percentage(35),
70	            ])
71	            .split(full_area)
72	    } else if has_dicom {
73	        Layout::default()
74	            .direction(Direction::Horizontal)
75	            .constraints([Constraint::Percentage(25), Constraint::Percentage(75)])
76	            .split(full_area)
77	    } else {
78	        Layout::default()
79	            .direction(Direction::Horizontal)
80	            .constraints([Constraint::Percentage(25), Constraint::Percentage(75)])
81	            .split(full_area)
82	    };
83	
84	    let explorer_area = columns[0];
85	    let explorer_focused = app.focus == Focus::Explorer;
86	
87	    if let Some(ref explorer) = app.explorer {
88	        let border_color = if explorer_focused {
89	            Color::Cyan
90	        } else {
91	            Color::DarkGray
92	        };
93	        let block = Block::default()
94	            .borders(Borders::ALL)
95	            .border_style(Style::default().fg(border_color))
96	            .title(format!(" {} ", explorer.cwd().display()));
97	
98	        let inner = block.inner(explorer_area);
99	        frame.render_widget(block, explorer_area);
100	        frame.render_widget_ref(explorer.widget(), inner);
101	    }
102	
103	    if has_dicom {
104	        let tags_area = columns[1];
105	
106	        let validation_height =
107	            if matches!(&app.validation_result, ValidationResult::Invalid(_)) {
108	                4
109	            } else {
110	                3
111	            };
112	
113	        let v_chunks = Layout::default()
114	            .direction(Direction::Vertical)
115	            .constraints([Constraint::Min(5), Constraint::Length(validation_height)])
116	            .split(tags_area);
117	
118	        render_tag_table(frame, v_chunks[0], app, true);
119	        render_validation_pane(frame, v_chunks[1], app);
120	
121	        if app.show_preview && columns.len() > 2 {
122	            render_preview_pane(frame, columns[2], app);
123	        }
124	
125	        render_explorer_help(frame, v_chunks[0], app);
126	    } else {
127	        let empty_area = columns[1];
128	        let block = Block::default()
129	            .borders(Borders::ALL)
130	            .border_style(Style::default().fg(Color::DarkGray))
131	            .title(" DICOM Viewer ");
132	        let paragraph = Paragraph::new("Select a DICOM file to view its tags")
133	            .style(Style::default().fg(Color::DarkGray))
134	            .block(block);
135	        frame.render_widget(paragraph, empty_area);
136	
137	        render_explorer_help(frame, explorer_area, app);
138	    }
139	}
140	
141	fn render_tag_table(frame: &mut Frame, area: Rect, app: &mut App, in_explorer: bool) {
142	    let mut header_cells = vec![];
143	    if app.diff_mode {
144	        header_cells.push(
145	            Cell::from(" ").style(
146	                Style::default()
147	                    .fg(Color::Yellow)
148	                    .add_modifier(Modifier::BOLD),
149	            ),
150	        );
151	    }
152	    header_cells.extend(vec![
153	        Cell::from("  Tag").style(
154	            Style::default()
155	                .fg(Color::Yellow)
156	                .add_modifier(Modifier::BOLD),
157	        ),
158	        Cell::from("Name").style(
159	            Style::default()
160	                .fg(Color::Yellow)
161	                .add_modifier(Modifier::BOLD),
162	        ),
163	        Cell::from("VR").style(
164	            Style::default()
165	                .fg(Color::Yellow)
166	                .add_modifier(Modifier::BOLD),
167	        ),
168	        Cell::from("Value").style(
169	            Style::default()
170	                .fg(Color::Yellow)
171	                .add_modifier(Modifier::BOLD),
172	        ),
173	    ]);
174	    let header = Row::new(header_cells).height(1);
175	
176	    let rows: Vec<Row> = app
177	        .tags
178	        .iter()
179	        .map(|tag| {
180	            let indent = "  ".repeat(tag.depth);
181	            let expand_indicator = if tag.is_expandable {
182	                if tag.is_expanded {
183	                    "▼ "
184	                } else {
185	                    "▶ "
186	                }
187	            } else {
188	                "  "
189	            };
190	            let tag_display = format!("{}{}{}", indent, expand_indicator, tag.tag);
191	
192	            let (row_style, value_cell) = if let Some(diff_status) = &tag.diff_status {
193	                match diff_status {
194	                    DiffStatus::Deleted => (
195	                        Style::default().fg(Color::Red),
196	                        Cell::from(tag.value.as_str()).style(Style::default().fg(Color::Red)),
197	                    ),
198	                    DiffStatus::Added => (
199	                        Style::default().fg(Color::Green),
200	                        Cell::from(tag.value.as_str()).style(Style::default().fg(Color::Green)),
201	                    ),
202	                    DiffStatus::Changed => {
203	                        let value_cell = if let Some(ref baseline) = tag.baseline_value {
204	                            let mut line = render_inline_diff(baseline, &tag.value);
205	                            if let Some(delta_ms) =
206	                                parse_dicom_datetime_delta_ms(&tag.vr, baseline, &tag.value)
207	                            {
208	                                let suffix = if delta_ms >= 0 {
209	                                    format!(" (+{} ms)", delta_ms)
210	                                } else {
211	                                    format!(" ({} ms)", delta_ms)
212	                                };
213	                                line.spans.push(Span::styled(
214	                                    suffix,
215	                                    Style::default().fg(Color::DarkGray),
216	                                ));
217	                            }
218	                            Cell::from(line)
219	                        } else {
220	                            Cell::from(tag.value.as_str()).style(Style::default().fg(Color::Blue))
221	                        };
222	                        (Style::default(), value_cell)
223	                    }
224	                    DiffStatus::Unchanged => (
225	                        Style::default(),
226	                        Cell::from(tag.value.as_str()).style(Style::default()),
227	                    ),
228	                }
229	            } else {
230	                let base_style = if tag.is_private() {
231	                    Style::default().fg(Color::DarkGray)
232	                } else {
233	                    Style::default()
234	                };
235	                (base_style, Cell::from(tag.value.as_str()).style(base_style))
236	            };
237	
238	            let mut row_cells = vec![];
239	
240	            if app.diff_mode {
241	                let (indicator, indicator_style) = if let Some(diff_status) = &tag.diff_status {
242	                    match diff_status {
243	                        DiffStatus::Added => ("+", Style::default().fg(Color::Green)),
244	                        DiffStatus::Deleted => ("-", Style::default().fg(Color::Red)),
245	                        DiffStatus::Changed => ("M", Style::default().fg(Color::Blue)),
246	                        DiffStatus::Unchanged => (" ", Style::default()),
247	                    }
248	                } else {
249	                    (" ", Style::default())
250	                };
251	                row_cells.push(Cell::from(indicator).style(indicator_style));
252	            }
253	
254	            row_cells.extend(vec![
255	                Cell::from(tag_display).style(row_style),
256	                Cell::from(tag.name.as_str()).style(row_style),
257	                Cell::from(tag.vr.as_str()).style(row_style),
258	                value_cell,
259	            ]);
260	
261	            Row::new(row_cells)
262	        })
263	        .collect();
264	
265	    let widths: Vec<Constraint> = if app.diff_mode {
266	        vec![
267	            Constraint::Length(1),
